/**
 * Splits an array into smaller arrays ("chunks") of a given size.
 * The final chunk may be smaller if the array doesn't divide evenly.
 *
 * @param {Array} items - The array to split up.
 * @param {number} chunkSize - How many items per chunk.
 * @returns {Array[]} An array of chunks.
 */
