  if (chunkSize <= 0) {
    throw new Error('chunkSize must be greater than 0');
  }

  const chunks = [];
  for (let i = 0; i < items.length; i += chunkSize) {
    chunks.push(items.slice(i, i + chunkSize));
  }

  return chunks;
}

/**
