/**
 * Flattens a nested array, recursing up to `depth` levels deep.
 *
 * @param {Array} array - The (possibly nested) array to flatten.
 * @param {number} [depth=1] - How many levels of nesting to flatten.
 * @returns {Array} A new, flattened array.
 */
function flatten(array, depth = 1) {
  if (depth < 1) {
